const image=document.getElementById("bg-image"),wrapper=document.getElementById("panzoom-wrapper"),viewport=document.getElementById("viewport");function initApp(){const panzoom=Panzoom(wrapper,{maxScale:12,minScale:1,contain:"outside",startScale:1});viewport.style.opacity="1";const parent=wrapper.parentElement;parent.addEventListener("wheel",panzoom.zoomWithWheel),window.innerWidth<768&&setTimeout(()=>{panzoom.zoom(1.5,{animate:!0})},500),wrapper.querySelectorAll(".hotspot").forEach(hotspot=>{hotspot.addEventListener("click",(function(e){e.stopPropagation(),alert(this.dataset.info)}))}),wrapper.addEventListener("click",e=>{if(e.target.classList.contains("hotspot"))return;const rect=wrapper.getBoundingClientRect(),x=(e.clientX-rect.left)/rect.width*100,y=(e.clientY-rect.top)/rect.height*100;console.log(`top: ${y.toFixed(1)}%; left: ${x.toFixed(1)}%;`)})}image.complete?initApp():(image.addEventListener("load",initApp),image.addEventListener("error",(function(){alert("Erro ao carregar a imagem. Verifique o caminho do arquivo.")})));